
.panel-page {
  display: flex;
  flex-direction: column;
  gap: 20px;
  min-width: 0;
  width: 100%;
}

.title-icon.green {
  color: #7ca982;
}

.member-sub-tabs {
  display: flex;
  gap: 10px;
  margin-bottom: 4px;
}

.sub-tab {
  flex: 1;
  padding: 10px 16px;
  border: 2px solid #e4d4ba;
  border-radius: 12px;
  background: #fcf8f0;
  color: #6b5a42;
  font-family: inherit;
  font-size: 15px;
  font-weight: 600;
  cursor: pointer;
  transition: border-color 0.15s, background 0.15s, color 0.15s;

  &:hover {
    background: #fffdf8;
    border-color: #d4c2a4;
  }

  &.active {
    background: #e8f0e4;
    border-color: #7ca982;
    color: #4a6b4f;
  }

  &.cubs-tab {
    color: #d46d8f;

    &:hover {
      border-color: #e8a0b8;
    }

    &.active {
      background: #fce8ef;
      border-color: #e8789a;
      color: #c94d73;
    }
  }
}

.cubs-sidebar-stats {
  color: #d46d8f;
  font-size: 0.68rem;
  font-weight: 800;
}

.cub-mother,
.cub-age {
  display: flex;
  align-items: center;
  gap: 4px;
}

.cubs-name {
  color: #c94d73;
}

.cub-race {
  background: #fce8ef;
  border-color: #e8a0b8;
  color: #b84a6a;
}

.cub-tag {
  color: #e8789a !important;
}

.cub-stat-pink {
  display: flex;
  align-items: center;
  gap: 5px;
  color: #e8789a;
}

.cub-avatar-placeholder {
  width: 88px;
  height: 88px;
  border-radius: 50%;
  border: 4px solid #e8789a;
  background: #fce8ef;
  display: flex;
  align-items: center;
  justify-content: center;
  position: relative;
  flex-shrink: 0;

  .cub-avatar-icon {
    position: absolute;
    color: #f0b8c8;
    opacity: 0.55;
  }

  .avatar-letter {
    z-index: 1;
    color: #c94d73;
  }
}

.cubs-icon {
  color: #e8789a;
}

.cub-rule-banner {
  margin: -8px 0 4px;
  padding: 12px 14px;
  border: 2px dashed #e8a0b8;
  border-radius: 14px;
  background: #fff8fa;
}

.cub-rule-label {
  margin: 0 0 6px;
  font-size: 0.72rem;
  font-weight: 900;
  color: #e8789a;
  letter-spacing: 0.06em;
}

.cub-rule-text {
  margin: 0;
  font-size: 0.8rem;
  font-weight: 700;
  color: #8c5a6a;
  line-height: 1.55;
}

.cub-growth-box {
  margin-top: 16px;
  padding: 14px 16px;
  border: 2px dashed #e8a0b8;
  border-radius: 14px;
  background: #fff8fa;
}

.cub-growth-label {
  margin: 0 0 8px;
  font-size: 0.72rem;
  font-weight: 900;
  color: #e8789a;
  letter-spacing: 0.06em;
}

.cub-growth-text {
  margin: 0;
  font-size: 0.82rem;
  font-weight: 700;
  color: #8c5a6a;
  line-height: 1.55;
}

.readonly-avatar {
  cursor: default;
}

.npc-role.muted {
  color: #9a8b72;
  font-style: italic;
}

.skill-section {
  margin-top: 4px;
  padding: 12px;
  border: 2px dashed #e4d4ba;
  border-radius: 12px;
  background: #faf6ee;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.skill-section-title {
  margin: 0;
  font-size: 13px;
  font-weight: 700;
  color: #6b5a42;
}

.skill-row {
  display: grid;
  grid-template-columns: 18px 36px 1fr 32px;
  align-items: center;
  gap: 6px;
}

.skill-icon {
  color: #8a7a62;
}

.skill-label {
  font-size: 13px;
  color: #5c4f3a;
  font-weight: 600;
}

.skill-bar-track {
  height: 8px;
  border-radius: 4px;
  background: #e8dcc8;
  overflow: hidden;
}

.skill-bar-fill {
  height: 100%;
  border-radius: 4px;
  transition: width 0.2s;

  &.skill-狩猎 {
    background: linear-gradient(90deg, #c47a4a, #e8a06a);
  }

  &.skill-战斗 {
    background: linear-gradient(90deg, #b54a4a, #e07070);
  }

  &.skill-采集 {
    background: linear-gradient(90deg, #5a9a5a, #7cb87c);
  }

  &.skill-后勤 {
    background: linear-gradient(90deg, #6a8ab5, #8aaed8);
  }
}

.skill-value {
  font-size: 12px;
  font-weight: 700;
  color: #5c4f3a;
  text-align: right;
  cursor: help;
}

.members-layout {
  display: flex;
  min-width: 0;
  width: 100%;
  min-height: 320px;
  overflow: hidden;
}

.member-sidebar {
  flex: 0 0 38%;
  max-width: 220px;
  min-width: 0;
  border-right: 2px dashed #e4d4ba;
  padding: 12px;
  overflow-y: auto;
  overflow-x: hidden;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.sidebar-item {
  display: flex;
  align-items: center;
  gap: 10px;
  width: 100%;
  padding: 10px;
  border: 2px solid #e4d4ba;
  border-radius: 14px;
  background: #fcf8f0;
  cursor: pointer;
  text-align: left;
  font-family: inherit;
  transition: border-color 0.15s, background 0.15s;

  &:hover {
    background: #fffdf8;
    border-color: #d4c2a4;
  }

  &.active {
    background: #f4ecdb;
    border-color: #c8955c;
    box-shadow: 0 2px 6px rgba(200, 149, 92, 0.2);
  }
}

.sidebar-avatar {
  width: 44px;
  height: 44px;
  border-radius: 12px;
  background: #dcd1be;
  border: 2px solid #c8955c;
  flex-shrink: 0;
  overflow: hidden;
  display: flex;
  align-items: center;
  justify-content: center;
  position: relative;
}

.sidebar-meta {
  min-width: 0;
  flex: 1;
}

.sidebar-name {
  display: block;
  font-weight: 900;
  color: #4a3b32;
  font-size: 0.95rem;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.sidebar-race {
  display: inline-block;
  margin-top: 2px;
  font-size: 0.62rem;
  background: #e4d4ba;
  color: #6b4c3a;
  padding: 1px 6px;
  border-radius: 999px;
  font-weight: 800;
}

.sidebar-stats {
  display: flex;
  gap: 10px;
  margin-top: 4px;
  font-size: 0.68rem;
  font-weight: 900;

  span {
    display: flex;
    align-items: center;
    gap: 3px;
  }
}

.member-detail {
  flex: 1 1 auto;
  min-width: 0;
  padding: 20px;
  position: relative;
  overflow-y: auto;
}

.expel-btn {
  position: absolute;
  top: 16px;
  right: 16px;
  color: #d9776c;
  background: transparent;
  border: none;
  padding: 8px;
  border-radius: 12px;
  cursor: pointer;
  z-index: 2;

  &:hover {
    color: #a8543f;
    background: #f4d8d3;
  }
}

.detail-head {
  display: flex;
  gap: 16px;
  margin-bottom: 16px;
  padding-right: 40px;
}

.avatar-label {
  width: 80px;
  height: 80px;
  border-radius: 16px;
  background: #dcd1be;
  border: 3px solid #c8955c;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  cursor: pointer;
  overflow: hidden;
  position: relative;
  box-shadow: 0 2px 6px rgba(0, 0, 0, 0.08);
}

.avatar-img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.avatar-bg-icon {
  position: absolute;
  color: #a88a6d;
  opacity: 0.3;
}

.avatar-letter {
  font-size: 1.4rem;
  font-weight: 900;
  color: #5c4738;
  z-index: 1;

  &.lg {
    font-size: 2rem;
  }
}

.avatar-hover {
  position: absolute;
  inset: 0;
  background: rgba(0, 0, 0, 0.4);
  color: #fff;
  font-size: 0.7rem;
  font-weight: 800;
  display: flex;
  align-items: center;
  justify-content: center;
  opacity: 0;
  transition: opacity 0.2s;
  z-index: 2;
}

.group-avatar:hover .avatar-hover {
  opacity: 1;
}

.hidden-input {
  display: none;
}

.npc-name {
  margin: 0;
  font-size: 1.35rem;
  font-weight: 900;
  color: #4a3b32;
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 8px;
}

.npc-race {
  font-size: 0.68rem;
  background: #e4d4ba;
  color: #6b4c3a;
  padding: 2px 8px;
  border-radius: 999px;
  font-weight: 800;
  border: 1px solid #d4c2a4;
}

.npc-role-row {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 10px;
  margin-top: 4px;
}

.npc-role {
  margin: 0;
  font-size: 0.82rem;
  font-weight: 700;
  color: #8c7462;
}

.npc-grade {
  display: inline-flex;
  align-items: center;
  padding: 2px 10px;
  border-radius: 999px;
  font-size: 0.75rem;
  font-weight: 900;
  letter-spacing: 0.04em;
  border: 1.5px solid currentColor;
}

.npc-grade.grade-beginner {
  color: #2e7d32;
  background: rgba(76, 175, 80, 0.12);
}

.npc-grade.grade-entry {
  color: #1565c0;
  background: rgba(33, 150, 243, 0.12);
}

.npc-grade.grade-skilled {
  color: #c62828;
  background: rgba(229, 57, 53, 0.12);
}

.npc-grade.grade-master {
  color: #f57f17;
  background: rgba(249, 168, 37, 0.16);
}

.npc-pregnancy {
  margin: 0;
  font-size: 0.82rem;
  font-weight: 800;
  color: #e8789a;
  letter-spacing: 0.04em;
}

.npc-stats {
  display: flex;
  flex-wrap: wrap;
  gap: 14px;
  margin-top: 10px;
  font-size: 0.78rem;
  font-weight: 900;

  span {
    display: flex;
    align-items: center;
    gap: 5px;
  }
}

.loyal {
  color: #d9776c;
}

.mood {
  color: #7ca982;
}

.stamina {
  color: #c8955c;
}

.stat-label {
  font-size: 0.72em;
  font-weight: 800;
  letter-spacing: 0.04em;
  opacity: 0.92;
}

.npc-info {
  padding-top: 14px;
  border-top: 2px dashed #e4d4ba;
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.info-line {
  display: flex;
  align-items: center;
  gap: 12px;
  font-size: 0.88rem;
  font-weight: 700;
  color: #6b4c3a;
  min-width: 0;

  span {
    overflow: hidden;
    text-overflow: ellipsis;
  }
}

.info-icon {
  color: #a88a6d;
  flex-shrink: 0;
}

.thought-box {
  margin-top: 16px;
  background: #fcf8f0;
  padding: 20px 16px 16px;
  border-radius: 12px;
  border: 1px solid #dcd1be;
  box-shadow: inset 0 1px 3px rgba(0, 0, 0, 0.04);
  position: relative;
}

.thought-box-label {
  margin: 0 0 8px;
  padding-left: 8px;
  font-size: 0.68rem;
  font-weight: 900;
  color: #c8955c;
  letter-spacing: 0.08em;
}

.thought-text {
  margin: 0;
  padding-left: 8px;
  font-size: 0.88rem;
  font-weight: 700;
  color: #5c4738;
  line-height: 1.55;
}

.thought-bubble {
  position: absolute;
  top: -12px;
  left: -8px;
  color: #c8955c;
  background: #f4ecdb;
  border-radius: 50%;
}

.interact-btn {
  width: 100%;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 12px;
  margin-top: 18px;
  font-size: 0.95rem;
}

.modal-panel.interact-modal {
  max-width: 420px;
  max-height: none;
  padding: 28px 24px 32px;
  text-align: center;
  overflow: visible;

  &::before {
    display: none;
  }
}

.interact-avatar-label {
  display: block;
  width: 96px;
  height: 96px;
  margin: 0 auto 14px;
  border-radius: 50%;
  border: 4px solid #c8955c;
  overflow: hidden;
  position: relative;
  cursor: pointer;
  box-shadow: 0 2px 6px rgba(0, 0, 0, 0.12);
}

.interact-avatar-img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.interact-avatar-placeholder {
  width: 100%;
  height: 100%;
  background: #dcd1be;
  display: flex;
  align-items: center;
  justify-content: center;
  position: relative;

  span {
    font-size: 2.2rem;
    font-weight: 900;
    color: #5c4738;
    z-index: 1;
  }
}

.placeholder-icon {
  position: absolute;
  color: #a88a6d;
  opacity: 0.3;
}

.interact-head h3 {
  margin: 0;
  font-size: 1.35rem;
  font-weight: 900;
  color: #4a3b32;
}

.interact-race {
  display: inline-block;
  margin-top: 6px;
  font-size: 0.78rem;
  font-weight: 700;
  color: #8c7462;
  background: #f4ecdb;
  padding: 4px 12px;
  border-radius: 999px;
}

.interact-panel {
  margin-top: 16px;
  text-align: left;
  background: #fffdf8;
  border: 2px dashed #c8955c;
  border-radius: 14px;
  padding: 14px 16px 20px;
  box-sizing: border-box;
  overflow: visible;
}

.gaze-box {
  min-width: 0;
}

.gaze-row {
  display: flex;
  gap: 10px;
  margin-bottom: 10px;
  font-size: 0.82rem;
  line-height: 1.45;
}

.gaze-label {
  flex-shrink: 0;
  font-weight: 900;
  color: #c8955c;
  min-width: 2.2em;
}

.gaze-text {
  font-weight: 700;
  color: #5c4738;
  min-width: 0;
}

.gaze-thought-label {
  display: block;
  margin-bottom: 6px;
  font-size: 0.66rem;
  font-weight: 900;
  color: #c8955c;
  letter-spacing: 0.06em;
}

.gaze-thought {
  position: relative;
  margin-top: 12px;
  padding: 12px 14px 10px;
  background: #fcf8f0;
  border-radius: 10px;

  p {
    margin: 0;
    font-size: 0.85rem;
    font-weight: 700;
    color: #6b4c3a;
    line-height: 1.55;
    padding: 0 8px;
  }
}

.gaze-quote-mark {
  font-size: 1.6rem;
  font-weight: 900;
  color: #e4d4ba;
  line-height: 1;

  &.end {
    float: right;
    margin-top: -8px;
  }
}

.interact-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 12px;
  margin-top: 14px;

  button:not(.breed-btn) {
    padding: 13px 8px;
    font-size: 1rem;
  }
}

.breed-btn {
  grid-column: 1 / -1;
  width: 100%;
  margin: 2px 0 0;
  padding: 14px 18px;
  box-sizing: border-box;
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  background: linear-gradient(180deg, #f8b4c8 0%, #e889a3 55%, #d96b8a 100%);
  color: #fff;
  border: 2px solid #c94d6a;
  border-radius: 14px;
  box-shadow:
    0 4px 0 #b83d5e,
    inset 0 1px 0 rgba(255, 255, 255, 0.35);
  font-weight: 900;
  font-size: 1.05rem;
  font-family: inherit;
  cursor: pointer;
  transition: all 0.15s ease;
  text-shadow: 0 1px 2px rgba(160, 50, 80, 0.35);

  &:hover {
    background: linear-gradient(180deg, #fcc0d2 0%, #ec96ae 55%, #e07895 100%);
    transform: translateY(2px);
    box-shadow:
      0 2px 0 #b83d5e,
      inset 0 1px 0 rgba(255, 255, 255, 0.35);
  }

  &:active {
    transform: translateY(4px);
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.2);
  }
}

.heart-badge {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 34px;
  height: 34px;
  border-radius: 50%;
  background: rgba(255, 255, 255, 0.22);
  border: 2px solid rgba(255, 255, 255, 0.5);
  box-shadow:
    inset 0 2px 4px rgba(255, 255, 255, 0.45),
    0 1px 3px rgba(180, 50, 80, 0.25);
}

.heart-icon {
  filter: drop-shadow(0 1px 1px rgba(180, 40, 70, 0.3));
}

.empty-hint {
  text-align: center;
  color: #8c7462;
  font-weight: 700;
  padding: 20px;
}

.feed-overlay {
  z-index: 350;
}

.feed-modal {
  width: min(100%, 380px);
  padding: 20px;
}

.feed-hint {
  margin: 0 0 12px;
  font-size: 0.85rem;
  color: #6b8f71;
  font-weight: 700;
  text-align: center;
}

.feed-list {
  display: flex;
  flex-direction: column;
  gap: 8px;
  max-height: 280px;
  overflow-y: auto;
}

.feed-item-btn {
  display: grid;
  grid-template-columns: 1fr auto;
  gap: 4px 10px;
  width: 100%;
  padding: 12px 14px;
  text-align: left;
  border: 2px solid #d4c4a8;
  border-radius: 12px;
  background: #fcf8f0;
  color: #5c4738;
  font-family: inherit;
  cursor: pointer;
  transition: border-color 0.15s ease, background 0.15s ease;

  &:hover {
    border-color: #7ca982;
    background: #f4faf4;
  }
}

.feed-item-name {
  font-weight: 900;
  font-size: 0.95rem;
}

.feed-item-meta {
  font-weight: 800;
  color: #6b8f71;
}

.feed-item-desc {
  grid-column: 1 / -1;
  font-size: 0.78rem;
  color: #8c7462;
  line-height: 1.4;
}

@media (max-width: 560px) {
  .members-layout {
    flex-direction: column;
  }

  .member-sidebar {
    flex: none;
    max-width: none;
    width: 100%;
    max-height: 160px;
    border-right: none;
    border-bottom: 2px dashed #e4d4ba;
    flex-direction: row;
    overflow-x: auto;
    overflow-y: hidden;
    flex-wrap: nowrap;
    scrollbar-width: none;

    &::-webkit-scrollbar {
      display: none;
    }
  }

  .sidebar-item {
    flex: 0 0 auto;
    min-width: 140px;
    max-width: 160px;
  }
}
