
.panel-page {
  display: flex;
  flex-direction: column;
  gap: 24px;
  padding-bottom: 16px;
}

.title-icon.map {
  color: #a88a6d;
}

.section {
  padding: 24px;
}

.section-head {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-bottom: 16px;

  h3 {
    margin: 0;
    font-size: 1.35rem;
    font-weight: 900;
    color: #5c4738;
  }

  &.between {
    justify-content: space-between;
  }

  &.border-b {
    padding-bottom: 14px;
    border-bottom: 2px dashed #e4d4ba;
    margin-bottom: 20px;
  }
}

.section-icon {
  color: #c8955c;

  &.muted {
    color: #a88a6d;
  }
}

.new-squad-btn {
  display: flex;
  align-items: center;
  gap: 4px;
  padding: 8px 14px;
  font-size: 0.82rem;
}

.squad-grid {
  display: grid;
  grid-template-columns: 1fr;
  gap: 14px;
}

.squad-card {
  background: #fcf8f0;
  border: 2px solid #e4d4ba;
  border-radius: 16px;
  padding: 16px;
  display: flex;
  flex-direction: column;
  transition: border-color 0.2s;

  &:hover {
    border-color: #c8955c;
  }
}

.squad-main {
  display: grid;
  grid-template-columns: 1fr minmax(140px, 200px);
  gap: 14px;
  align-items: start;
  margin-bottom: 12px;
}

.squad-left {
  min-width: 0;
}

.squad-eval {
  background: #fdfbf7;
  border: 2px dashed #d4c2a4;
  border-radius: 12px;
  padding: 10px 12px;
}

.eval-title {
  margin: 0 0 4px;
  font-size: 0.75rem;
  font-weight: 900;
  color: #8c7462;
}

.eval-cap {
  font-size: 0.65rem;
  font-weight: 700;
  color: #a88a6d;
}

.eval-formula {
  margin: 0 0 8px;
  font-size: 0.6rem;
  font-weight: 700;
  color: #a88a6d;
}

.skill-line {
  display: grid;
  grid-template-columns: 36px 1fr auto;
  gap: 6px;
  align-items: center;
  font-size: 0.72rem;
  font-weight: 700;
  color: #5c4738;
  margin-bottom: 4px;

  strong {
    color: #a8543f;
    font-size: 0.82rem;
  }
}

.skill-tier {
  font-size: 0.62rem;
  color: #8c7462;
}

.action-eval {
  margin-top: 10px;
  padding-top: 10px;
  border-top: 1px dashed #e4d4ba;
}

.action-mechanism-block {
  & + & {
    margin-top: 10px;
    padding-top: 10px;
    border-top: 1px dashed #efe4d4;
  }
}

.action-focus {
  margin: 4px 0 6px;
  font-size: 0.64rem;
  font-weight: 700;
  color: #8c7462;
  line-height: 1.4;
}

.output-tiers {
  margin: 0 0 6px;
  padding: 0;
  list-style: none;

  li {
    margin: 0 0 3px;
    font-size: 0.62rem;
    font-weight: 700;
    color: #6b4c3a;
    line-height: 1.35;
  }
}

.tier-tag {
  display: inline-block;
  min-width: 2.2em;
  margin-right: 4px;
  padding: 1px 4px;
  border-radius: 4px;
  font-size: 0.58rem;
  font-weight: 900;
  background: #f4ecdb;
  color: #7a6554;
}

.eval-result {
  margin: 4px 0 0;
  font-size: 0.68rem;
  font-weight: 700;
  color: #6b4c3a;
  line-height: 1.45;
}

.eval-label {
  display: block;
  font-size: 0.72rem;
  font-weight: 900;
  color: #7ca982;

  &.探索 {
    color: #7ca982;
  }

  &.狩猎 {
    color: #c47a4a;
  }

  &.采集 {
    color: #b87a41;
  }
}

.squad-head {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 10px;

  h4 {
    margin: 0;
    font-size: 1.05rem;
    font-weight: 900;
    color: #4a3b32;
  }
}

.squad-status-row {
  display: flex;
  align-items: center;
  gap: 6px;
}

.disband-btn {
  color: #d9776c;
  background: transparent;
  border: none;
  padding: 4px;
  border-radius: 6px;
  cursor: pointer;

  &:hover {
    color: #a8543f;
    background: #f4d8d3;
  }
}

.status-badge {
  font-size: 0.65rem;
  font-weight: 800;
  padding: 3px 8px;
  border-radius: 999px;
  border: 1px solid;

  &.idle {
    background: #eef5ef;
    color: #4a7c59;
    border-color: #7ca982;
  }

  &.gather {
    background: #f4ecdb;
    color: #b87a41;
    border-color: #e6b981;
  }

  &.explore {
    background: #f4d8d3;
    color: #a8543f;
    border-color: #d9776c;
  }
}

.member-box {
  background: #fdfbf7;
  border: 1px solid #e4d4ba;
  border-radius: 12px;
  padding: 12px;
  margin-bottom: 12px;
}

.member-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  margin-bottom: 10px;
}

.member-tag {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  background: #e4d4ba;
  color: #5c4738;
  font-size: 0.75rem;
  font-weight: 800;
  padding: 4px 6px 4px 10px;
  border-radius: 8px;
}

.tag-remove {
  border: none;
  background: none;
  color: #8c7462;
  cursor: pointer;
  padding: 0;
  display: flex;

  &:hover:not(:disabled) {
    color: #a8543f;
  }

  &:disabled {
    opacity: 0.3;
    cursor: not-allowed;
  }
}

.add-member {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  border: 2px dashed #c8955c;
  background: transparent;
  color: #c8955c;
  font-size: 0.72rem;
  font-weight: 800;
  padding: 4px 8px;
  border-radius: 8px;
  cursor: pointer;
  font-family: inherit;

  &:hover {
    background: #e4d4ba;
  }
}

.stepper-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding-top: 10px;
  border-top: 1px dashed #d4c2a4;
  font-size: 0.82rem;
  font-weight: 800;
  color: #6b4c3a;

  strong {
    color: #a8543f;
  }
}

.stepper-btns {
  display: flex;
  gap: 6px;

  button {
    width: 24px;
    height: 24px;
    border: none;
    border-radius: 6px;
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;

    &:first-child {
      background: #f4d8d3;
      color: #a8543f;
    }

    &:last-child {
      background: #cde4d1;
      color: #4a7c59;
    }

    &:disabled {
      opacity: 0.4;
      cursor: not-allowed;
      background: #fcf8f0;
    }
  }
}

.squad-foot {
  font-size: 0.7rem;
  font-weight: 700;
  color: #8c7462;
  text-align: right;
  margin-top: 6px;
  line-height: 1.45;
}

.pool-hint {
  display: block;
  font-size: 0.62rem;
  font-weight: 600;
  color: #a88a6d;
  margin-top: 2px;
}

.duration-stepper {
  pointer-events: auto;

  &:has(button:disabled) {
    opacity: 1;
  }
}

.stepper-row:has(.duration-stepper) {
  .duration-stepper {
    opacity: 1;
  }
}

.squad-actions {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 8px;

  &.three-cols {
    grid-template-columns: repeat(3, 1fr);
  }
}

.dispatch-explore,
.dispatch-gather,
.dispatch-hunt {
  padding: 10px;
  border-radius: 12px;
  font-size: 0.85rem;
  font-weight: 900;
  border: none;
  cursor: pointer;
  transition: background 0.2s;

  &:disabled {
    opacity: 0.5;
    cursor: not-allowed;
  }
}

.dispatch-explore {
  background: #7ca982;
  color: #fff;

  &:hover:not(:disabled) {
    background: #638568;
  }
}

.dispatch-hunt {
  background: #c47a4a;
  color: #fff;

  &:hover:not(:disabled) {
    background: #a86438;
  }
}

.dispatch-gather {
  background: #e6b981;
  color: #634326;

  &:hover:not(:disabled) {
    background: #d4a86a;
  }
}

.status-badge.hunt {
  background: #f4e8db;
  color: #a86438;
  border-color: #c47a4a;
}

.dispatch-focus {
  margin: 0 0 8px;
  font-size: 0.78rem;
  font-weight: 700;
  color: #8c7462;
  line-height: 1.45;
}

.modal-tiers {
  margin-bottom: 10px;
}

.dispatch-eval-preview {
  margin: 0 0 14px;
  padding: 10px 12px;
  background: #f8f4ec;
  border: 1px dashed #e4d4ba;
  border-radius: 10px;
  font-size: 0.78rem;
  font-weight: 700;
  color: #6b4c3a;
  line-height: 1.45;
}

.area-filter-hint {
  margin: 6px 0 0;
  font-size: 0.68rem;
  font-weight: 700;
  color: #a8543f;
}

.explore-accent {
  color: #7ca982;
}

.gather-accent {
  color: #b87a41;
}

.dispatch-go-btn {
  &.探索 {
    background: #7ca982;
    color: #fff;
  }

  &.狩猎 {
    background: #c47a4a;
    color: #fff;
  }

  &.采集 {
    background: #e6b981;
    color: #634326;
  }
}

.night-hint {
  margin: 10px 0 0;
  padding: 10px 12px;
  border-radius: 10px;
  background: #2a2438;
  color: #d4c8f0;
  font-size: 0.78rem;
  font-weight: 700;
  line-height: 1.5;
}

.dynamic-gen-hint {
  margin: 0 0 12px;
  padding: 8px 10px;
  background: #eef5ef;
  border: 1px dashed #7ca982;
  border-radius: 8px;
  font-size: 0.72rem;
  font-weight: 700;
  color: #4a7c59;
  line-height: 1.45;
}

.pack-empty-hint {
  margin: 0 0 12px;
  font-size: 0.72rem;
  font-weight: 700;
  color: #8c7462;
}

.dispatch-modal {
  max-width: 520px;
}

.hunt-accent {
  color: #c47a4a;
}

.hunt-eval-preview {
  margin: 0 0 14px;
  padding: 10px 12px;
  background: #fdf6ee;
  border: 1px dashed #e6b981;
  border-radius: 10px;
  font-size: 0.78rem;
  font-weight: 700;
  color: #6b4c3a;
  line-height: 1.45;
}

.hunt-pack-head {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 4px;
}

.pack-weight {
  font-size: 0.75rem;
  font-weight: 800;
  color: #7ca982;

  &.over {
    color: #a8543f;
  }
}

.pack-hint {
  margin: 0 0 10px;
  font-size: 0.68rem;
  font-weight: 700;
  color: #8c7462;
}

.hunt-pack-grid {
  display: grid;
  grid-template-columns: 1fr;
  gap: 8px;
  max-height: 42vh;
  overflow: auto;
  margin-bottom: 14px;
}

.pack-item-card {
  padding: 10px 12px;
  border: 2px solid #e4d4ba;
  border-radius: 12px;
  background: #fffdf8;
}

.pack-item-top {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 8px;
  margin-bottom: 4px;
}

.pack-item-name {
  font-weight: 900;
  color: #4a3b32;
  font-size: 0.88rem;
}

.pack-bonus-tag {
  font-size: 0.62rem;
  font-weight: 800;
  color: #a86438;
  background: #f4e8db;
  padding: 2px 6px;
  border-radius: 6px;
  white-space: nowrap;
}

.pack-item-hint {
  margin: 0 0 8px;
  font-size: 0.68rem;
  font-weight: 700;
  color: #8c7462;
}

.pack-item-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.pack-stock {
  font-size: 0.72rem;
  font-weight: 700;
  color: #6b4c3a;
}

.pack-stepper {
  display: flex;
  align-items: center;
  gap: 8px;

  button {
    width: 26px;
    height: 26px;
    border: none;
    border-radius: 6px;
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    background: #f4ecdb;
    color: #5c4738;

    &:disabled {
      opacity: 0.35;
      cursor: not-allowed;
    }
  }

  strong {
    min-width: 1.2em;
    text-align: center;
    color: #a8543f;
  }
}

.hunt-go-btn {
  margin-top: 4px;
}

@media (max-width: 640px) {
  .squad-actions.three-cols {
    grid-template-columns: 1fr;
  }
}

.area-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 14px;
}

.area-card {
  padding: 20px;
  cursor: pointer;
  border-left: 4px solid #7ca982;
  transition: background 0.2s;

  &.danger {
    border-left-color: #d9776c;
  }

  &:hover {
    background: #fffdf8;
  }

  h4 {
    margin: 0;
    font-weight: 900;
    color: #4a3b32;
    font-size: 1.05rem;
  }

  p {
    margin: 8px 0;
    font-size: 0.85rem;
    font-weight: 700;
    color: #8c7462;
    line-height: 1.45;
  }
}

.area-head {
  display: flex;
  align-items: center;
  gap: 10px;
}

.area-icon.safe {
  color: #7ca982;
}

.area-icon.danger {
  color: #d9776c;
}

.area-foot {
  display: flex;
  justify-content: space-between;
  align-items: center;
  font-size: 0.75rem;
  font-weight: 900;
  color: #7ca982;
}

.journal-card {
  border: 2px solid #c8955c;
  border-radius: 12px;
  background: #fffdf8;
  margin-bottom: 12px;
  cursor: pointer;
  transition: transform 0.2s;
  overflow: hidden;

  &:hover:not(.handled) {
    transform: translateY(-1px);
  }

  &.handled {
    border-color: #e4d4ba;
    opacity: 0.6;
    cursor: default;
  }
}

.journal-head {
  padding: 16px;
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.journal-title {
  font-weight: 900;
  color: #4a3b32;
  font-size: 1.05rem;
  display: flex;
  align-items: center;
  gap: 6px;
}

.check-icon {
  color: #7ca982;
}

.journal-meta {
  font-size: 0.72rem;
  font-weight: 700;
  color: #8c7462;
  margin-top: 4px;

  .time {
    color: #c8955c;
  }
}

.chevron {
  color: #c8955c;
  transition: transform 0.3s;

  &.open {
    transform: rotate(90deg);
  }
}

.journal-body {
  padding: 0 16px 16px;
  border-top: 1px dashed #e4d4ba;
  background: #fcf8f0;

  p {
    margin: 16px 0;
    font-size: 0.88rem;
    font-weight: 700;
    color: #5c4738;
    line-height: 1.5;
  }
}

.archive-btn {
  float: right;
  padding: 8px 20px;
  font-size: 0.85rem;
}

.handled-badge {
  font-size: 0.65rem;
  background: #e4d4ba;
  padding: 4px 8px;
  border-radius: 6px;
  font-weight: 800;
  color: #8c7462;
}

.modal-head {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-bottom: 20px;

  h3 {
    margin: 0;
    font-weight: 900;
    font-size: 1.35rem;
    color: #5c4738;
  }

  .accent {
    color: #c8955c;
  }
}

.w-full {
  width: 100%;
  padding: 14px;
  margin-top: 8px;
}

.pick-list {
  max-height: 50vh;
  overflow: auto;
}

.pick-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 12px;
  border: 2px solid #e4d4ba;
  border-radius: 12px;
  background: #fcf8f0;
  margin-bottom: 8px;
}

.pick-name {
  font-weight: 900;
  color: #4a3b32;
  display: block;
}

.pick-race {
  font-size: 0.72rem;
  font-weight: 700;
  color: #8c7462;
  background: #e4d4ba;
  padding: 2px 8px;
  border-radius: 999px;
  margin-top: 4px;
  display: inline-block;
}

.pick-btn {
  padding: 6px 12px;
  font-size: 0.82rem;
}

.area-desc-box {
  background: #fcf8f0;
  border: 2px solid #e4d4ba;
  border-radius: 12px;
  padding: 14px;
  margin-bottom: 16px;
  font-weight: 700;
  color: #8c7462;
  font-size: 0.88rem;
}

.area-actions {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 10px;
  margin-top: 16px;

  button {
    padding: 10px;
  }
}

.ignore-area-btn {
  grid-column: 1 / -1;
  margin-top: 4px;
  padding: 12px;
  background: #f4d8d3;
  color: #a8543f;
  border: 2px solid #d9776c;
  border-radius: 12px;
  box-shadow: 0 4px 0 #d9776c;
  font-weight: 900;
  font-family: inherit;
  cursor: pointer;
  transition: all 0.15s;

  &:hover {
    transform: translateY(2px);
    box-shadow: 0 2px 0 #d9776c;
  }

  &:active {
    transform: translateY(4px);
    box-shadow: none;
  }
}

.empty-hint {
  text-align: center;
  color: #8c7462;
  font-weight: 700;
  padding: 16px;
}

@media (max-width: 640px) {
  .squad-main {
    grid-template-columns: 1fr;
  }

  .area-grid {
    grid-template-columns: 1fr;
  }
}
