
.tabs-shell {
  position: relative;
  flex: 1 1 auto;
  min-width: 0;
  display: flex;
  align-items: center;
  gap: 2px;

  &.can-scroll-left .tabs {
    mask-image: linear-gradient(90deg, transparent 0, #000 28px, #000 calc(100% - 28px), transparent 100%);
  }

  &.can-scroll-right:not(.can-scroll-left) .tabs {
    mask-image: linear-gradient(90deg, #000 0, #000 calc(100% - 28px), transparent 100%);
  }
}

.tabs {
  display: flex;
  flex: 1 1 auto;
  min-width: 0;
  align-items: center;
  gap: 4px;
  flex-wrap: nowrap;
  overflow-x: auto;
  overflow-y: hidden;
  scroll-behavior: smooth;
  -webkit-overflow-scrolling: touch;
  overscroll-behavior-x: contain;
  scrollbar-width: none;
  -ms-overflow-style: none;
  padding: 2px 4px;

  &::-webkit-scrollbar {
    display: none;
  }
}

.scroll-btn {
  flex-shrink: 0;
  width: 28px;
  height: 28px;
  border: 1px solid #d4c2a4;
  border-radius: 8px;
  background: #fcf8f0;
  color: #8c7462;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  padding: 0;
  transition: background 0.15s;

  &:hover {
    background: #e4d4ba;
    color: #5c4738;
  }
}

.tab-button {
  display: inline-flex;
  align-items: center;
  flex-shrink: 0;
  padding: 10px 14px;
  border: 2px solid transparent;
  border-radius: 12px;
  background: transparent;
  color: #8c7462;
  font-family: inherit;
  font-size: 0.84rem;
  font-weight: 800;
  cursor: pointer;
  transition: all 0.2s ease;
  white-space: nowrap;
}

.tab-button:hover {
  background: #e4d4ba;
  color: #6b4c3a;
}

.tab-button.active {
  background: #7ca982;
  color: #fff;
  border-color: #5b8266;
  box-shadow: 0 3px 8px rgba(91, 130, 102, 0.35);
  transform: scale(1.02);
}

.tab-svg {
  margin-right: 8px;
  flex-shrink: 0;
}

.tab-svg.pulse {
  animation: iconPulse 2s ease-in-out infinite;
}

.tab-label {
  line-height: 1;
}

@keyframes iconPulse {
  0%,
  100% {
    opacity: 1;
  }

  50% {
    opacity: 0.65;
  }
}

@media (max-width: 520px) {
  .tab-button {
    padding: 8px 10px;
    font-size: 0.76rem;
  }

  .tab-svg {
    margin-right: 5px;
  }

  .scroll-btn {
    width: 24px;
    height: 24px;
  }
}
