
.panel-page {
  display: flex;
  flex-direction: column;
  gap: 20px;
  padding-bottom: 16px;
}

.title-icon {
  color: #c8955c;
}

.stat-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 14px;
}

.population-card {
  grid-column: 1 / -1;
  padding: 16px 18px;
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.population-head {
  display: flex;
  align-items: center;
  gap: 12px;
}

.population-total {
  margin: 0;
  font-size: 1.75rem;
  font-weight: 900;
  color: #4a3b32;
  line-height: 1.1;
}

.population-label {
  margin: 4px 0 0;
  font-size: 0.72rem;
  font-weight: 700;
  color: #8c7462;
  letter-spacing: 0.04em;
}

.population-breakdown {
  list-style: none;
  margin: 0;
  padding: 0;
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(120px, 1fr));
  gap: 8px;
}

.population-breakdown li {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 8px;
  padding: 8px 10px;
  border-radius: 10px;
  background: rgba(255, 255, 255, 0.45);
  border: 1px solid #e4d4ba;
}

.population-race {
  font-size: 0.82rem;
  font-weight: 800;
  color: #5c4738;
}

.population-count {
  font-size: 0.82rem;
  font-weight: 900;
  color: #6b8f71;
}

@media (min-width: 640px) {
  .stat-grid {
    grid-template-columns: minmax(220px, 1.35fr) repeat(3, 1fr);
  }

  .population-card {
    grid-column: auto;
    grid-row: span 1;
  }
}

.icon-people {
  color: #5c4738;
}

.icon-food {
  color: #e07a5f;
}

.icon-shelter {
  color: #7ca982;
}

.icon-cohesion {
  color: #d9776c;
}

.camp-layout {
  display: grid;
  grid-template-columns: 1.1fr 0.9fr;
  gap: 20px;
}

.camp-side {
  display: flex;
  flex-direction: column;
  gap: 20px;
}

.section {
  padding: 22px;
}

.section-head {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 18px;

  h3 {
    margin: 0;
    font-size: 1.15rem;
    font-weight: 900;
    color: #5c4738;
  }
}

.section-icon {
  color: #c8955c;
}

.resource-row {
  margin-bottom: 16px;
}

.warehouse-footer {
  margin-top: 20px;
  padding-top: 16px;
  border-top: 2px dashed #e4d4ba;
}

.warehouse-lv {
  margin: 0 0 6px;
  font-size: 0.82rem;
  font-weight: 900;
  color: #5c4738;
}

.warehouse-cost {
  margin: 0 0 12px;
  font-size: 0.72rem;
  font-weight: 800;
  color: #d9776c;
  line-height: 1.45;

  &.enough {
    color: #4a7c59;
  }

  &.maxed {
    color: #8c7462;
  }
}

.warehouse-btn-wrap {
  display: flex;
  gap: 10px;
}

.warehouse-upgrade-btn {
  flex: 1;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  padding: 12px 10px;
  font-size: 0.88rem;
  white-space: nowrap;

  &:disabled {
    opacity: 0.45;
    cursor: not-allowed;
    transform: none;
    box-shadow: 0 4px 0 #5b8266;
  }
}

.warehouse-btn {
  flex: 1;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  background: #e6b981;
  color: #5c4738;
  border: 2px solid #c8955c;
  border-radius: 12px;
  font-weight: 900;
  font-family: inherit;
  padding: 12px 24px;
  cursor: pointer;
  box-shadow: 0 4px 0 #c8955c;
  transition: all 0.15s;

  &:hover {
    transform: translateY(2px);
    box-shadow: 0 2px 0 #c8955c;
  }

  &:active {
    transform: translateY(4px);
    box-shadow: none;
  }
}

.defense-card {
  display: flex;
  align-items: center;
}

.defense-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 12px;
  width: 100%;
}

.defense-info {
  display: flex;
  align-items: center;
  gap: 14px;
}

.defense-icon {
  color: #8c7462;
  flex-shrink: 0;
}

.defense-lv {
  font-size: 1.5rem;
  font-weight: 900;
  color: #5c4738;
  margin: 4px 0 0;
}

.defense-cost {
  margin: 6px 0 0;
  font-size: 0.72rem;
  font-weight: 800;
  color: #d9776c;

  &.enough {
    color: #4a7c59;
  }
}

.defense-btn {
  padding: 10px 18px;
  white-space: nowrap;

  &:disabled {
    opacity: 0.45;
    cursor: not-allowed;
    transform: none;
    box-shadow: 0 4px 0 #5b8266;
  }
}

.building-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  margin-bottom: 20px;
}

.building-tag {
  background: #fdfbf7;
  border: 2px solid #d4c2a4;
  padding: 8px 14px;
  border-radius: 12px;
  font-size: 0.85rem;
  font-weight: 900;
  color: #6b4c3a;
  box-shadow: 0 1px 2px rgba(0, 0, 0, 0.04);
}

.btn-row {
  display: flex;
  gap: 10px;

  button {
    flex: 1;
    padding: 12px 8px;
    font-size: 0.88rem;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 6px;
  }
}

.modal-head {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-bottom: 18px;

  h3 {
    margin: 0;
    font-weight: 900;
    font-size: 1.35rem;
    color: #5c4738;
  }

  .accent {
    color: #c8955c;
  }
}

.wide {
  max-width: 640px;
}

.item-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 12px;
}

.item-card {
  background: #fcf8f0;
  border: 2px solid #e4d4ba;
  border-radius: 12px;
  padding: 16px;
  text-align: center;
  transition: all 0.2s;

  &:hover {
    border-color: #c8955c;
    transform: scale(1.03);
  }
}

.item-icon {
  font-size: 2.2rem;
  display: block;
  margin-bottom: 8px;
}

.item-name {
  font-weight: 900;
  font-size: 0.82rem;
  color: #5c4738;
  display: block;
}

.item-qty {
  font-size: 0.7rem;
  font-weight: 900;
  color: #a88a6d;
  background: #f4ecdb;
  padding: 2px 6px;
  border-radius: 4px;
  margin-top: 6px;
  display: inline-block;
}

.w-full {
  width: 100%;
  padding: 14px;
}

.plan-modal {
  max-width: 560px;
  width: min(96vw, 560px);
}

.plan-tabs {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 10px;
  margin-bottom: 12px;
}

.plan-tab {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  padding: 12px;
  border: 2px solid #8c7462;
  border-radius: 12px;
  background: #fcf8f0;
  font-weight: 900;
  font-size: 0.85rem;
  color: #6b4c3a;
  cursor: pointer;
  font-family: inherit;

  &.active {
    border-color: #4a7c59;
    background: #e8f3eb;
    color: #3d5c45;
  }
}

.plan-detail {
  min-height: 240px;
  max-height: 420px;
  border: 2px dashed #e4d4ba;
  border-radius: 14px;
  background: #fcf8f0;
  padding: 14px;
  margin-bottom: 14px;
}

.catalog-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 10px;
  margin-top: 10px;
}

@media (max-width: 520px) {
  .catalog-grid {
    grid-template-columns: 1fr;
  }
}

.plan-info {
  h4 {
    margin: 0 0 10px;
    font-size: 0.95rem;
    font-weight: 900;
    color: #3d5c45;
  }
}

.info-row {
  margin: 6px 0;
  font-size: 0.78rem;
  font-weight: 700;
  color: #5c4738;
  line-height: 1.45;

  span {
    font-weight: 900;
    color: #4a7c59;
    margin-right: 6px;
  }
}

.form-field.compact {
  margin-bottom: 10px;
}

.plan-confirm {
  margin-top: 0;

  &:disabled {
    opacity: 0.45;
    cursor: not-allowed;
  }
}

.plan-preview {
  background: #f4ecdb;
  border: 2px dashed #c8955c;
  border-radius: 12px;
  padding: 14px;
  margin-bottom: 16px;
}

.plan-preview-title {
  margin: 0 0 10px;
  font-size: 0.82rem;
  font-weight: 900;
  color: #5c4738;
}

.plan-preview-row {
  display: flex;
  gap: 10px;
  margin: 6px 0;
  font-size: 0.85rem;
  font-weight: 700;
  color: #6b4c3a;
}

.plan-preview-label {
  flex-shrink: 0;
  font-weight: 900;
  color: #8c7462;
  min-width: 2.5em;
}

.plan-preview-hint {
  margin: 10px 0 0;
  font-size: 0.72rem;
  font-weight: 800;
  color: #4a7c59;

  &.shortage {
    color: #d9776c;
  }
}

.materials-box {
  background: #fdf6e8;
  border-color: #c8955c;
}

.hours-box {
  background: #eef0f5;
  border-color: #8c7462;
}

.facility-modal {
  max-width: 720px;
  position: relative;
  overflow: hidden;
  padding-top: 18px;
  padding-bottom: 18px;
}

.facility-layout {
  display: flex;
  align-items: stretch;
  max-height: 68vh;
  min-height: 260px;
  overflow: hidden;
}

.facility-list {
  width: 50%;
  padding-right: 14px;
  border-right: 2px dashed #e4d4ba;
  overflow-y: auto;

  h3 {
    font-size: 1.2rem;
    font-weight: 900;
    margin: 0 0 14px;
    color: #5c4738;
    display: flex;
    align-items: center;
    gap: 8px;
  }
}

.facility-item {
  display: block;
  width: 100%;
  text-align: left;
  padding: 14px;
  margin-bottom: 8px;
  border: 2px solid #d4c2a4;
  border-radius: 12px;
  background: #fcf8f0;
  font-family: inherit;
  font-weight: 900;
  color: #4a3b32;
  cursor: pointer;
  transition: background 0.15s;

  &:hover {
    background: #fffdf8;
  }

  &.active {
    background: #f4ecdb;
    border-color: #c8955c;
  }
}

.facility-detail {
  width: 50%;
  padding-left: 20px;
  overflow: hidden;

  h4 {
    font-size: 1.3rem;
    font-weight: 900;
    color: #4a3b32;
    margin: 0 0 10px;
    padding-top: 0;
  }
}

.detail-box {
  background: #fcf8f0;
  border: 2px solid #e4d4ba;
  border-radius: 12px;
  padding: 12px;
  margin-bottom: 12px;

  p {
    margin: 0;
    font-weight: 700;
    color: #8c7462;
    font-size: 0.88rem;
    line-height: 1.5;
  }
}

.effect-box {
  margin-top: 12px;
  background: #eef5ef;
  border: 1px solid #7ca982;
  border-radius: 8px;
  padding: 10px;
  font-weight: 700;
  font-size: 0.85rem;
  color: #5c4738;

  .effect-label {
    display: block;
    font-size: 0.68rem;
    font-weight: 900;
    color: #4a7c59;
    margin-bottom: 4px;
  }
}

.facility-actions {
  display: flex;
  flex-direction: column;
  gap: 8px;
  padding-top: 10px;
  border-top: 2px dashed #e4d4ba;

  .actions-label {
    font-size: 0.82rem;
    font-weight: 900;
    color: #8c7462;
  }

  button {
    padding: 10px;
    font-size: 0.88rem;
  }
}

.facility-empty {
  width: 50%;
  padding-left: 24px;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  text-align: center;
  color: #a88a6d;
  font-weight: 700;

  .empty-icon {
    opacity: 0.2;
    margin-bottom: 16px;
  }
}

.empty-hint {
  text-align: center;
  color: #8c7462;
  font-weight: 700;
  padding: 20px;
}

@media (max-width: 640px) {
  .camp-layout {
    grid-template-columns: 1fr;
  }

  .facility-layout {
    flex-direction: column;
  }

  .facility-list,
  .facility-detail,
  .facility-empty {
    width: 100%;
    border-right: none;
    padding: 0;
  }

  .facility-list {
    border-bottom: 2px dashed #e4d4ba;
    padding-bottom: 16px;
    margin-bottom: 16px;
  }
}
