
.panel-page {
  display: flex;
  flex-direction: column;
  gap: 24px;
}

.title-flame {
  color: #e07a5f;
  flex-shrink: 0;
}

.fuel-flame {
  color: #d9776c;
}

.affairs-crown {
  color: #e6b981;
  flex-shrink: 0;
}

.info-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 20px;
}

.info-grid.compact {
  gap: 12px;
}

.info-card {
  padding: 20px;
}

.info-row {
  display: flex;
  align-items: center;
  gap: 16px;
}

.info-value {
  font-size: 1.15rem;
  font-weight: 800;
  color: #4a3b32;
  margin: 4px 0 0;
}

.calendar-line {
  font-size: 0.92rem;
  font-weight: 900;
  color: #8c7462;
  letter-spacing: 0.04em;
}

.fuel-panel {
  padding: 28px;
}

.fuel-head {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 12px;
  margin-bottom: 12px;
  flex-wrap: wrap;
}

.fuel-title {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 1.15rem;
  font-weight: 900;
  color: #5c4738;
}

.fuel-time {
  font-weight: 900;
}

.fuel-foot {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 12px;
  margin-top: 14px;
  flex-wrap: wrap;
}

.fuel-opinion {
  flex: 1;
  min-width: 180px;
  margin: 0;
  font-size: 0.88rem;
  font-weight: 700;
  color: #6b4c3a;
  line-height: 1.5;
}

.add-fuel-btn {
  flex-shrink: 0;
  padding: 8px 14px;
  font-size: 0.85rem;
}

.fuel-stock-hint {
  margin: 8px 0 0;
  font-size: 0.75rem;
  font-weight: 700;
  color: #8c7462;
}

.info-grid.three-cols {
  grid-template-columns: repeat(3, 1fr);
}

.highlight-cell .stat-value {
  color: #a8543f;
}

@media (max-width: 560px) {
  .info-grid.three-cols {
    grid-template-columns: 1fr;
  }
}

.affairs-panel {
  padding: 28px;
}

.affairs-title {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-bottom: 20px;
  font-size: 1.4rem;

  h3 {
    margin: 0;
    font-size: 1.4rem;
    font-weight: 900;
    color: #5c4738;
  }
}

.affair-group {
  margin-bottom: 20px;
}

.affair-level {
  display: flex;
  align-items: center;
  font-size: 0.9rem;
  font-weight: 900;
  color: #8c7462;
  margin: 0 0 10px;
}

.meeting-btn {
  width: 100%;
  margin-top: 24px;
  padding: 14px;
  font-size: 1.05rem;
}

.mvu-panel {
  padding: 20px;
}

.mvu-title {
  font-size: 0.95rem;
  font-weight: 900;
  color: #5c4738;
  margin: 0 0 12px;
}

.mvu-cell {
  background: rgba(255, 255, 255, 0.45);
  border: 1px solid #e4d4ba;
  border-radius: 12px;
  padding: 12px;
}

.empty-hint {
  text-align: center;
  color: #8c7462;
  font-weight: 700;
  font-size: 0.88rem;
}

.modal-close {
  position: absolute;
  top: 16px;
  right: 16px;
  width: 32px;
  height: 32px;
  border: 1px solid #d4c2a4;
  border-radius: 50%;
  background: #fcf8f0;
  color: #a88a6d;
  font-size: 1.2rem;
  font-weight: 900;
  cursor: pointer;
  z-index: 2;
}

.modal-head {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-bottom: 20px;
  font-size: 1.4rem;

  h3 {
    margin: 0;
    font-size: 1.4rem;
    font-weight: 900;
    color: #5c4738;
  }
}

.radio-row {
  display: flex;
  gap: 20px;
}

.radio-item {
  display: flex;
  align-items: center;
  gap: 8px;
  font-weight: 700;
  color: #5c4738;
  cursor: pointer;

  input {
    position: absolute;
    opacity: 0;
    pointer-events: none;
  }
}

.radio-dot {
  width: 20px;
  height: 20px;
  border-radius: 50%;
  border: 2px solid #d4c2a4;
  display: flex;
  align-items: center;
  justify-content: center;

  &.on.primary::after {
    content: '';
    width: 10px;
    height: 10px;
    border-radius: 50%;
    background: #e07a5f;
  }

  &.on.secondary::after {
    content: '';
    width: 10px;
    height: 10px;
    border-radius: 50%;
    background: #7ca982;
  }
}

.w-full {
  width: 100%;
  padding: 14px;
  font-size: 1.05rem;
  margin-top: 8px;
}

@media (max-width: 560px) {
  .info-grid {
    grid-template-columns: 1fr;
  }
}
