
.game-loading {
  width: 420px;
  margin: 32px auto;
  padding: 28px 24px;
  text-align: center;
  font-weight: 800;
  color: #6b4c3a;

  p {
    margin: 12px 0 0;
    font-size: 0.92rem;
  }
}

.loading-paw {
  color: #c8955c;
  animation: pawSpin 1.4s ease-in-out infinite;
}

@keyframes pawSpin {
  0%,
  100% {
    transform: rotate(-8deg) scale(1);
    opacity: 0.7;
  }

  50% {
    transform: rotate(8deg) scale(1.08);
    opacity: 1;
  }
}

.top-bar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
  padding: 10px 10px 10px 12px;
  margin: 18px 14px 0;
  flex-wrap: nowrap;
  overflow: visible;
}

.undo-btn {
  flex-shrink: 0;
  padding: 6px 10px;
  border: 2px dashed #c8955c;
  border-radius: 10px;
  background: #fcf8f0;
  color: #6b4c3a;
  font-size: 0.68rem;
  font-weight: 900;
  cursor: pointer;
  white-space: nowrap;

  &:hover:not(:disabled) {
    background: #f4ecdb;
    border-color: #a88a6d;
  }

  &:disabled {
    opacity: 0.45;
    cursor: not-allowed;
  }
}

:deep(.top-user) {
  flex-shrink: 0;
}

.content-area {
  padding: 0 14px 22px;
}

.content-wrap {
  max-width: 56rem;
  margin: 0 auto;
  min-width: 0;
  width: 100%;
}

.paw-layer {
  position: absolute;
  inset: 0;
  pointer-events: none;
  overflow: hidden;
  opacity: 0.1;
  z-index: 0;
  color: #5c4738;
}

.paw {
  position: absolute;
}

.paw-1 {
  top: -40px;
  left: -40px;
  transform: rotate(45deg);
  opacity: 0.5;
}

.paw-2 {
  top: 140px;
  left: 100px;
  transform: rotate(60deg);
  opacity: 0.4;
}

.paw-3 {
  bottom: 30px;
  right: 24px;
  transform: rotate(-12deg);
  opacity: 0.5;
}

.paw-4 {
  top: 28%;
  right: 22%;
  transform: rotate(80deg);
  opacity: 0.6;
}
