
.assign-modal {
  max-width: 440px;
  width: 100%;
  padding: 22px;
}

.modal-head {
  display: flex;
  align-items: flex-start;
  gap: 12px;
  margin-bottom: 14px;

  h3 {
    margin: 0;
    font-size: 1.15rem;
    font-weight: 900;
    color: #4a3b32;
  }
}

.modal-subtitle {
  margin: 4px 0 0;
  font-size: 0.78rem;
  font-weight: 700;
  color: #8c7462;
}

.accent {
  color: #c8955c;
  flex-shrink: 0;
}

.member-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  margin-bottom: 12px;
}

.member-tag {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  background: #f4ecdb;
  border: 1px solid #c8955c;
  padding: 4px 10px;
  border-radius: 999px;
  font-size: 0.78rem;
  font-weight: 800;
  color: #5c4738;
}

.tag-remove {
  border: none;
  background: transparent;
  color: #a88a6d;
  cursor: pointer;
  padding: 0;
  display: flex;
}

.pick-list {
  max-height: 220px;
  margin-bottom: 14px;
}

.pick-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
  padding: 10px 0;
  border-bottom: 1px dashed #e4d4ba;

  &:last-child {
    border-bottom: none;
  }
}

.pick-name {
  display: block;
  font-weight: 900;
  color: #4a3b32;
}

.pick-race {
  display: block;
  margin-top: 2px;
  font-size: 0.72rem;
  color: #8c7462;
  font-weight: 700;
}

.pick-btn {
  flex-shrink: 0;
  padding: 6px 14px;
  font-size: 0.82rem;
}

.stepper-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
  padding: 10px 12px;
  border: 2px dashed #e4d4ba;
  border-radius: 12px;
  background: #faf6ee;
  font-size: 0.85rem;
  font-weight: 700;
  color: #5c4738;

  strong {
    color: #c8955c;
    font-size: 1rem;
  }
}

.stepper-btns {
  display: flex;
  gap: 6px;

  button {
    width: 32px;
    height: 32px;
    border: 1px solid #e4d4ba;
    border-radius: 8px;
    background: #fffdf8;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #5c4738;

    &:disabled {
      opacity: 0.4;
      cursor: not-allowed;
    }

    &:last-child {
      background: #eef5ef;
      border-color: #7ca982;
      color: #4a7c59;
    }
  }
}

.staff-hint {
  margin: 8px 0 14px;
  font-size: 0.68rem;
  font-weight: 700;
  color: #9a8b72;
  text-align: right;
}

.confirm-btn {
  width: 100%;
  padding: 12px;
}

.empty-hint {
  text-align: center;
  color: #8c7462;
  font-weight: 700;
  padding: 12px;
}
