
.panel-page {
  display: flex;
  flex-direction: column;
  gap: 20px;
  padding-bottom: 16px;
  min-width: 0;
  width: 100%;
}

.title-icon {
  color: #8c7462;
}

.section {
  padding: 22px;
}

.queue-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
  margin-bottom: 16px;
  padding-bottom: 12px;
  border-bottom: 2px dashed #e4d4ba;
}

.queue-title {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 1.15rem;
  font-weight: 900;
  margin: 0;

  &.brown {
    color: #5c4738;
  }

  &.amber {
    color: #b87a41;
  }

  &.red {
    color: #a8543f;
  }
}

.work-card {
  background: #fffdf8;
  border: 2px solid #e4d4ba;
  border-radius: 16px;
  padding: 16px;
  margin-bottom: 12px;
  transition: border-color 0.2s;

  &:hover {
    border-color: #c8955c;
  }

  &:last-child {
    margin-bottom: 0;
  }
}

.work-main {
  display: flex;
  align-items: center;
  gap: 14px;
}

.work-icon {
  width: 48px;
  height: 48px;
  background: #fcf8f0;
  border: 2px solid #e4d4ba;
  border-radius: 12px;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  box-shadow: inset 0 1px 3px rgba(0, 0, 0, 0.06);
  color: #5c4738;
}

.work-body {
  flex: 1;
  min-width: 0;
}

.work-head {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 8px;
  gap: 8px;
}

.work-name {
  font-weight: 900;
  color: #4a3b32;
  font-size: 1rem;
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: 6px;
}

.work-tag {
  font-size: 0.65rem;
  background: #e4d4ba;
  color: #6b4c3a;
  padding: 2px 6px;
  border-radius: 6px;
  font-weight: 800;
}

.efficiency-badge {
  font-size: 0.62rem;
  background: #eef5ef;
  color: #4a7c59;
  border: 1px solid #7ca982;
  padding: 2px 6px;
  border-radius: 6px;
  font-weight: 800;
}

.hours-badge {
  font-size: 0.62rem;
  background: #eef0f5;
  color: #5c4738;
  border: 1px solid #8c7462;
  padding: 2px 6px;
  border-radius: 6px;
  font-weight: 800;
}

.work-pct {
  font-size: 0.85rem;
  font-weight: 900;
  color: #8c7462;
  flex-shrink: 0;
}

.work-ctrl {
  display: flex;
  gap: 6px;
  flex-shrink: 0;
}

.ctrl-btn {
  width: 38px;
  height: 38px;
  border: 1px solid #e4d4ba;
  border-radius: 12px;
  background: #fdfbf7;
  color: #8c7462;
  cursor: pointer;
  box-shadow: 0 1px 2px rgba(0, 0, 0, 0.06);
  transition: background 0.15s;
  display: flex;
  align-items: center;
  justify-content: center;

  &:hover {
    background: #e4d4ba;
    color: #5c4738;
  }

  &.stop {
    color: #e07a5f;

    &:hover {
      background: #f4d8d3;
      color: #a8543f;
    }
  }
}

.staff-box {
  margin-top: 14px;
  padding-top: 14px;
  border-top: 2px dashed #e4d4ba;
  background: #fdfbf7;
  border-radius: 12px;
  padding: 12px;
}

.member-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  margin-bottom: 10px;
}

.member-tag {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  background: #e4d4ba;
  color: #5c4738;
  font-size: 0.75rem;
  font-weight: 800;
  padding: 4px 6px 4px 10px;
  border-radius: 8px;

  &.readonly-tag {
    padding: 4px 10px;
  }
}

.coop-tag {
  display: inline-flex;
  align-items: center;
  background: #eef5ef;
  color: #4a7c59;
  border: 1px solid #7ca982;
  font-size: 0.72rem;
  font-weight: 800;
  padding: 4px 10px;
  border-radius: 8px;
}

.staff-box.readonly {
  .member-tags {
    margin-bottom: 0;
  }
}

.tag-remove {
  border: none;
  background: none;
  color: #8c7462;
  cursor: pointer;
  padding: 0;
  display: flex;

  &:hover:not(:disabled) {
    color: #a8543f;
  }

  &:disabled {
    opacity: 0.3;
    cursor: not-allowed;
  }
}

.add-member {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  border: 2px dashed #c8955c;
  background: transparent;
  color: #c8955c;
  font-size: 0.72rem;
  font-weight: 800;
  padding: 4px 8px;
  border-radius: 8px;
  cursor: pointer;
  font-family: inherit;

  &:hover:not(:disabled) {
    background: #e4d4ba;
  }

  &:disabled {
    opacity: 0.4;
    cursor: not-allowed;
  }
}

.stepper-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  font-size: 0.82rem;
  font-weight: 800;
  color: #6b4c3a;

  strong {
    color: #a8543f;
  }
}

.stepper-btns {
  display: flex;
  gap: 6px;

  button {
    width: 24px;
    height: 24px;
    border: none;
    border-radius: 6px;
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;

    &:first-child {
      background: #f4d8d3;
      color: #a8543f;
    }

    &:last-child {
      background: #cde4d1;
      color: #4a7c59;
    }

    &:disabled {
      opacity: 0.4;
      cursor: not-allowed;
      background: #fcf8f0;
    }
  }
}

.staff-hint {
  margin: 8px 0 0;
  font-size: 0.65rem;
  font-weight: 600;
  color: #a88a6d;
  text-align: right;
}

.modal-head {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-bottom: 16px;

  h3 {
    margin: 0;
    font-weight: 900;
    color: #5c4738;
  }

  .accent {
    color: #c8955c;
  }
}

.pick-list {
  max-height: 50vh;
  overflow: auto;
}

.pick-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 12px;
  border: 2px solid #e4d4ba;
  border-radius: 12px;
  background: #fcf8f0;
  margin-bottom: 8px;
}

.pick-name {
  font-weight: 900;
  color: #4a3b32;
  display: block;
}

.pick-race {
  font-size: 0.72rem;
  font-weight: 700;
  color: #8c7462;
  background: #e4d4ba;
  padding: 2px 8px;
  border-radius: 999px;
  margin-top: 4px;
  display: inline-block;
}

.pick-btn {
  padding: 6px 12px;
  font-size: 0.82rem;
}

.empty-hint {
  text-align: center;
  color: #8c7462;
  font-weight: 700;
  padding: 16px;
}

.era-progress-btn {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 6px 12px;
  border: 2px dashed #c8955c;
  border-radius: 10px;
  background: #fffdf8;
  color: #c8955c;
  font-size: 0.78rem;
  font-weight: 800;
  font-family: inherit;
  cursor: pointer;
  white-space: nowrap;

  &:hover {
    background: #f4ecdb;
  }
}

.add-project-btn {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 6px 12px;
  border: 2px dashed #c8955c;
  border-radius: 10px;
  background: #fffdf8;
  color: #c8955c;
  font-size: 0.78rem;
  font-weight: 800;
  font-family: inherit;
  cursor: pointer;
  flex-shrink: 0;

  &:hover {
    background: #f4ecdb;
  }
}

.project-modal {
  max-width: 520px;
}

.project-list {
  max-height: 55vh;
  overflow: auto;
}

.era-section {
  margin-bottom: 10px;

  &.locked .era-head {
    opacity: 0.55;
    cursor: not-allowed;
  }
}

.era-head {
  display: flex;
  align-items: center;
  gap: 8px;
  width: 100%;
  padding: 10px 12px;
  border: 2px dashed #c8955c;
  border-radius: 10px;
  background: #f4ecdb;
  font-weight: 900;
  font-size: 0.82rem;
  color: #5c4738;
  cursor: pointer;
  font-family: inherit;
  text-align: left;

  &:disabled {
    cursor: not-allowed;
  }
}

.era-lock-tag {
  margin-left: auto;
  font-size: 0.68rem;
  color: #d9776c;
}

.era-count {
  margin-left: auto;
  font-size: 0.68rem;
  color: #8c7462;
}

.project-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 10px;
  margin-top: 8px;
}

.project-card {
  display: flex;
  gap: 8px;
  padding: 10px;
  border: 2px solid #e4d4ba;
  border-radius: 12px;
  background: #fffdf8;
  text-align: left;
  cursor: pointer;
  font-family: inherit;
  transition: border-color 0.15s;

  &:hover:not(.locked) {
    border-color: #c8955c;
    background: #fcf8f0;
  }

  &.locked {
    opacity: 0.5;
    cursor: not-allowed;
    background: #f5f0e8;
  }

  p {
    margin: 0 0 4px;
    font-size: 0.72rem;
    font-weight: 700;
    color: #6b4c3a;
    line-height: 1.35;
  }
}

.project-thumb {
  width: 48px;
  height: 48px;
  flex-shrink: 0;
  border: 2px solid #e6b981;
  border-radius: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 0.65rem;
  font-weight: 900;
  color: #a8543f;
  background: #fdf6e8;
}

.project-lock {
  color: #8c7462 !important;
  font-weight: 900 !important;

  &.shortage {
    color: #d9776c !important;
  }
}

.project-ready {
  color: #4a7c59 !important;
  font-weight: 900 !important;
}

.project-card.ready {
  border-color: #4a7c59;
  background: #f0f7f2;
}

.pending-badge {
  font-size: 0.62rem;
  font-weight: 900;
  color: #fff;
  background: #8c7462;
  padding: 2px 6px;
  border-radius: 6px;
  margin-left: 4px;
}

.assign-hint {
  margin: 6px 0 0;
  font-size: 0.68rem;
  font-weight: 800;
  color: #8c7462;
}

.project-name {
  font-weight: 900 !important;
  color: #4a3b32 !important;
}

.project-meta {
  min-width: 0;
}

@media (max-width: 480px) {
  .project-grid {
    grid-template-columns: 1fr;
  }
}
