
.confirm-overlay {
  z-index: 200;
}

.confirm-panel {
  width: min(100%, 360px);
  padding: 24px;
  text-align: center;
}

.confirm-title {
  margin: 0 0 12px;
  font-size: 1.15rem;
  font-weight: 900;
  color: #4a3b32;
}

.confirm-message {
  margin: 0 0 20px;
  font-size: 0.92rem;
  font-weight: 700;
  color: #6b4c3a;
  line-height: 1.55;
  white-space: pre-wrap;
}

.confirm-actions {
  display: flex;
  gap: 10px;
}

.confirm-actions .tribal-button-alt,
.confirm-ok {
  flex: 1;
  min-width: 0;
  padding: 10px 14px;
  border-radius: 12px;
  font-size: 0.88rem;
  font-weight: 900;
  font-family: inherit;
  cursor: pointer;
}

.confirm-ok {
  border: 2px solid #7ca982;
  background: #7ca982;
  color: #fff;

  &.danger {
    border-color: #d9776c;
    background: #d9776c;
  }
}
