
.title-card {
  padding: 40px 28px 32px;
  text-align: center;
  overflow: hidden;
}

.title-aura {
  position: absolute;
  top: 72px;
  left: 50%;
  width: 280px;
  height: 140px;
  margin-left: -140px;
  background: radial-gradient(ellipse at center, rgba(200, 149, 92, 0.22) 0%, transparent 72%);
  pointer-events: none;
  animation: auraPulse 4s ease-in-out infinite;
}

@keyframes auraPulse {
  0%,
  100% {
    opacity: 0.55;
    transform: scale(1);
  }

  50% {
    opacity: 1;
    transform: scale(1.06);
  }
}

.corner {
  position: absolute;
  width: 24px;
  height: 24px;
  border: 2px solid rgba(200, 149, 92, 0.55);
  pointer-events: none;
}

.corner-tl {
  top: 12px;
  left: 12px;
  border-right: none;
  border-bottom: none;
  border-radius: 6px 0 0 0;
}

.corner-tr {
  top: 12px;
  right: 12px;
  border-left: none;
  border-bottom: none;
  border-radius: 0 6px 0 0;
}

.corner-bl {
  bottom: 12px;
  left: 12px;
  border-right: none;
  border-top: none;
  border-radius: 0 0 0 6px;
}

.corner-br {
  bottom: 12px;
  right: 12px;
  border-left: none;
  border-top: none;
  border-radius: 0 0 6px 0;
}

.float-deco {
  position: absolute;
  inset: 0;
  pointer-events: none;
  color: #c8955c;
}

.deco {
  position: absolute;
  opacity: 0.65;
}

.spark-1 {
  top: 48px;
  left: 36px;
}

.star-1 {
  top: 56px;
  right: 40px;
  color: #e6b981;
}

.paw-1 {
  bottom: 96px;
  left: 28px;
  opacity: 0.35;
}

.paw-2 {
  bottom: 108px;
  right: 32px;
  opacity: 0.3;
}

.title-eyebrow {
  margin: 0 0 10px;
  font-size: 0.68rem;
  font-weight: 800;
  letter-spacing: 0.32em;
  color: #a88a6d;
}

.game-title {
  margin: 0;
  font-size: 2.6rem;
  font-weight: 900;
  line-height: 1.15;
  color: #4a3b32;
  letter-spacing: 0.1em;
  perspective: 400px;
}

.title-char {
  display: inline-block;
  text-shadow: 0 2px 0 rgba(255, 255, 255, 0.35), 0 4px 12px rgba(92, 71, 56, 0.15);
}

.title-divider {
  width: min(200px, 60%);
  height: 2px;
  margin: 16px auto 14px;
  background: linear-gradient(90deg, transparent, #d4c2a4 20%, #c8955c 50%, #d4c2a4 80%, transparent);
  transform: scaleX(0.4);
  position: relative;
}

.divider-gem {
  position: absolute;
  top: 50%;
  left: 50%;
  width: 10px;
  height: 10px;
  margin: -5px 0 0 -5px;
  background: #e6b981;
  border: 2px solid #c8955c;
  border-radius: 2px;
  transform: rotate(45deg);
  box-shadow: 0 0 10px rgba(200, 149, 92, 0.4);
}

.title-tagline {
  margin: 0 0 16px;
  font-size: 0.84rem;
  font-weight: 700;
  color: #8c7462;
  line-height: 1.65;
  letter-spacing: 0.04em;
  padding: 0 8px;
}

.author-notice {
  margin: 0 0 20px;
  padding: 12px 14px;
  border: 2px dashed #e4d4ba;
  border-radius: 12px;
  background: rgba(255, 253, 248, 0.85);
  text-align: left;
}

.author-notice-title {
  margin: 0 0 8px;
  font-size: 0.78rem;
  font-weight: 900;
  color: #c8955c;
  letter-spacing: 0.12em;
}

.author-notice-list {
  margin: 0;
  padding-left: 1.15em;
  font-size: 0.68rem;
  font-weight: 700;
  color: #6b4c3a;
  line-height: 1.55;

  li {
    margin-bottom: 4px;

    &:last-child {
      margin-bottom: 0;
    }
  }

  strong {
    color: #5c4738;
    font-weight: 900;
  }
}

.start-btn {
  position: relative;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  max-width: 100%;
  width: 260px;
  padding: 15px 24px;
  border: 2px solid #5b8266;
  border-radius: 16px;
  background: linear-gradient(180deg, #8dbd93 0%, #7ca982 45%, #6a9470 100%);
  color: #fdfbf7;
  font-size: 1.05rem;
  font-weight: 900;
  font-family: inherit;
  letter-spacing: 0.1em;
  cursor: pointer;
  overflow: hidden;
  box-shadow: 0 5px 0 #5b8266, inset 0 1px 0 rgba(255, 255, 255, 0.35);
  text-shadow: 0 1px 2px rgba(0, 0, 0, 0.12);
  transition: filter 0.2s ease;

  &:disabled {
    cursor: wait;
    filter: saturate(0.85);
  }

  &:active:not(:disabled) {
    transform: translateY(3px);
    box-shadow: 0 2px 0 #5b8266, inset 0 1px 0 rgba(255, 255, 255, 0.25);
  }
}

.start-shine {
  position: absolute;
  top: 0;
  left: -120px;
  width: 80px;
  height: 100%;
  background: linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.35), transparent);
  transform: skewX(-18deg);
  animation: shineSweep 3.5s ease-in-out infinite;
}

@keyframes shineSweep {
  0%,
  55% {
    left: -120px;
  }

  100% {
    left: 320px;
  }
}

.start-icon {
  flex-shrink: 0;
}

.start-arrow {
  flex-shrink: 0;
  opacity: 0.85;
  transition: transform 0.2s ease;
}

.start-btn:hover:not(:disabled) .start-arrow {
  transform: translateX(3px);
}

.title-hint {
  margin: 14px 0 0;
  font-size: 0.7rem;
  font-weight: 700;
  color: #b5a389;
  letter-spacing: 0.06em;
}
